#!/usr/bin/env node
/**
 * select-mvp-activities.mjs
 *
 * Picks the Phase 1 "Money MVP" activity set out of the full ~1,500 catalogue
 * and writes a durable allow-list to `src/data/mvp-slugs.json`.
 *
 * WHY an allow-list (not a flag written into per-activity JSON):
 *   The source of truth is `src/data/activities.ts`. `content/activities/*.json`
 *   and `.content/generated/*.json` are BUILD ARTIFACTS regenerated by
 *   `scripts/content-build.mjs` on every dev/build. Writing `mvp:true` directly
 *   into those files would be overwritten on the next build. Instead we keep one
 *   reversible source — the slug allow-list — and `content-build.mjs` stamps
 *   `mvp: <bool>` onto every activity (and list item) from it, so the flag
 *   reaches the generated JSON the runtime reads and survives rebuilds. This
 *   mirrors the existing `src/data/launch-fifty.ts` pattern.
 *
 * Selection criteria (MVP_LAUNCH_PLAN.md §2 Day 1):
 *   1. Confirmed non-stock photo  — slug present in the curated photo set
 *      (`activity-images.json`) or the matched SwissActivities photo set
 *      (`activity-images-swissactivities.json`). The legacy generic
 *      `imageUrl` Unsplash shots and the category fallback do NOT count.
 *   2. >=1 real marketplace listing — a `marketplaces[]` entry with
 *      `isDirectLink === true` and a real booking URL (deep link, not a
 *      search template).
 *   3. Even distribution across the 5 MVP destinations.
 *
 * Usage:
 *   node scripts/select-mvp-activities.mjs                 # 200, default 5 dests
 *   node scripts/select-mvp-activities.mjs --count=100
 *   node scripts/select-mvp-activities.mjs --destinations=Zurich,Lucerne,Interlaken,Zermatt,Geneva
 *   node scripts/select-mvp-activities.mjs --dry-run       # report only, no writes
 *
 * After running, run `npm run content:build` so the stamp propagates.
 */

import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");

const GENERATED_FULL = resolve(ROOT, ".content/generated/activities.full.json");
const SA_IMAGES = resolve(ROOT, "src/data/activity-images-swissactivities.json");
const CURATED_IMAGES = resolve(ROOT, "src/data/activity-images.json");
const SA_PRICES = resolve(ROOT, ".content/swissactivities-prices.json");
const OUT_ALLOWLIST = resolve(ROOT, "src/data/mvp-slugs.json");
const OUT_REPORT = resolve(ROOT, ".content/mvp-selection-report.json");

// ─── Args ─────────────────────────────────────────────────────────────────────
const ARGV = process.argv.slice(2);
function arg(name, fallback) {
  const hit = ARGV.find((a) => a.startsWith(`--${name}=`));
  return hit ? hit.slice(name.length + 3) : fallback;
}
const COUNT = Math.max(1, Number(arg("count", "200")) || 200);
const DRY_RUN = ARGV.includes("--dry-run");
const DESTINATIONS = String(arg("destinations", "Zurich,Lucerne,Interlaken,Zermatt,Geneva"))
  .split(",")
  .map((s) => s.trim())
  .filter(Boolean);

// ─── Destination matchers ─────────────────────────────────────────────────────
// city  → strongest signal (exact city / city substring)
// keyword → name/tag/subcategory mentions a place in this destination's cluster
// region → location.region falls in this destination's area (weakest)
const DEST_CONFIG = {
  Zurich: {
    cities: ["zurich", "zürich"],
    keywords: ["zurich", "zürich", "uetliberg", "lindt", "fifa"],
    region: /zurich/i,
  },
  Lucerne: {
    cities: ["lucerne", "luzern", "engelberg", "weggis", "vitznau"],
    keywords: ["lucerne", "luzern", "pilatus", "rigi", "stanserhorn", "titlis", "bürgenstock", "engelberg", "lake lucerne"],
    region: /lucerne|lake lucerne|central switzerland/i,
  },
  Interlaken: {
    cities: ["interlaken", "grindelwald", "lauterbrunnen", "wengen", "mürren", "murren", "brienz", "thun", "spiez", "kandersteg"],
    keywords: ["interlaken", "jungfrau", "grindelwald", "lauterbrunnen", "schilthorn", "harder kulm", "brienz", "bernese oberland", "first", "trümmelbach", "trummelbach", "oeschinen"],
    region: /bernese oberland/i,
  },
  Zermatt: {
    cities: ["zermatt", "saas-fee", "saas fee", "täsch", "tasch", "zinal", "sion"],
    keywords: ["zermatt", "matterhorn", "gornergrat", "saas-fee", "saas fee", "aletsch"],
    region: /valais/i,
  },
  Geneva: {
    cities: ["geneva", "genève", "geneve", "lausanne", "montreux", "vevey", "nyon"],
    keywords: ["geneva", "genève", "geneve", "lausanne", "montreux", "lavaux", "chillon", "cern", "jet d'eau", "lake geneva"],
    region: /geneva|lake geneva|vaud/i,
  },
};

// destinations that are configured (intersection with --destinations)
const ACTIVE_DESTS = DESTINATIONS.filter((d) => DEST_CONFIG[d]);
const UNKNOWN_DESTS = DESTINATIONS.filter((d) => !DEST_CONFIG[d]);
if (UNKNOWN_DESTS.length) {
  console.warn(`⚠  No matcher for destination(s): ${UNKNOWN_DESTS.join(", ")} — ignored. Add them to DEST_CONFIG.`);
}
if (ACTIVE_DESTS.length === 0) {
  console.error("✗ No usable destinations. Aborting.");
  process.exit(1);
}

// ─── Load data ────────────────────────────────────────────────────────────────
if (!existsSync(GENERATED_FULL)) {
  console.error(`✗ ${GENERATED_FULL} not found. Run \`npm run content:build\` first.`);
  process.exit(1);
}
const activities = JSON.parse(readFileSync(GENERATED_FULL, "utf8"));
const saImages = JSON.parse(readFileSync(SA_IMAGES, "utf8")).images ?? {};
const curatedImages = existsSync(CURATED_IMAGES)
  ? JSON.parse(readFileSync(CURATED_IMAGES, "utf8")).images ?? {}
  : {};
const saPrices = existsSync(SA_PRICES) ? JSON.parse(readFileSync(SA_PRICES, "utf8")) : {};

// ─── Criteria helpers ─────────────────────────────────────────────────────────
function hasConfirmedPhoto(a) {
  const curated = curatedImages[a.slug]?.src;
  const sa = saImages[a.slug]?.src;
  if (curated) return "curated";
  if (sa) return "swissactivities";
  return null;
}

function realMarketplaces(a) {
  return (a.marketplaces ?? []).filter(
    (m) => m && m.isDirectLink === true && typeof m.bookingUrl === "string" && /^https?:\/\//.test(m.bookingUrl),
  );
}

function hasPriceData(a) {
  const p = saPrices[a.slug];
  return Boolean(p && Number.isFinite(Number(p.minAdult)) && Number(p.minAdult) > 0);
}

function matchDestination(a) {
  const city = (a.location?.city ?? "").toLowerCase();
  const region = a.location?.region ?? "";
  const hay = [a.name, a.subcategory, ...(a.tags ?? [])].join(" ").toLowerCase();
  let best = null;
  let bestScore = 0;
  for (const dest of ACTIVE_DESTS) {
    const cfg = DEST_CONFIG[dest];
    let score = 0;
    if (cfg.cities.some((c) => city === c || city.includes(c))) score = 3;
    else if (cfg.keywords.some((k) => hay.includes(k))) score = 2;
    else if (cfg.region.test(region)) score = 1;
    if (score > bestScore) {
      bestScore = score;
      best = dest;
    }
  }
  return best ? { dest: best, score: bestScore } : null;
}

// ─── Build candidate pool ─────────────────────────────────────────────────────
const stats = {
  total: activities.length,
  failedPhoto: 0,
  failedMarketplace: 0,
  unmatchedDestination: 0,
  eligible: 0,
};

const buckets = Object.fromEntries(ACTIVE_DESTS.map((d) => [d, []]));

for (const a of activities) {
  if (a.published === false) continue; // never promote quarantined activities
  const photo = hasConfirmedPhoto(a);
  if (!photo) {
    stats.failedPhoto++;
    continue;
  }
  const mkts = realMarketplaces(a);
  if (mkts.length < 1) {
    stats.failedMarketplace++;
    continue;
  }
  const dm = matchDestination(a);
  if (!dm) {
    stats.unmatchedDestination++;
    continue;
  }
  stats.eligible++;

  const priced = hasPriceData(a);
  const quality =
    dm.score * 4 +
    (photo === "curated" ? 3 : 2) +
    (priced ? 3 : 0) +
    (a.featured ? 1 : 0) +
    (mkts.length > 1 ? 1 : 0) +
    (mkts.some((m) => Number.isFinite(m.rating)) ? 1 : 0);

  buckets[dm.dest].push({ slug: a.slug, name: a.name, dest: dm.dest, quality, priced, photo });
}

for (const d of ACTIVE_DESTS) buckets[d].sort((x, y) => y.quality - x.quality);

// ─── Even distribution with shortfall redistribution ──────────────────────────
const n = ACTIVE_DESTS.length;
const base = Math.floor(COUNT / n);
const remainder = COUNT - base * n;
// Give the +1 remainder slots to the destinations with the deepest pools.
const byDepth = [...ACTIVE_DESTS].sort((a, b) => buckets[b].length - buckets[a].length);
const quota = Object.fromEntries(ACTIVE_DESTS.map((d) => [d, base]));
for (let i = 0; i < remainder; i++) quota[byDepth[i % n]]++;

const selected = [];
const taken = Object.fromEntries(ACTIVE_DESTS.map((d) => [d, 0]));
for (const d of ACTIVE_DESTS) {
  const take = Math.min(quota[d], buckets[d].length);
  for (let i = 0; i < take; i++) {
    selected.push(buckets[d][i]);
    taken[d]++;
  }
}
// Redistribute any shortfall (a bucket too shallow) to buckets with surplus.
let deficit = COUNT - selected.length;
while (deficit > 0) {
  let progressed = false;
  for (const d of byDepth) {
    if (deficit <= 0) break;
    if (buckets[d].length > taken[d]) {
      selected.push(buckets[d][taken[d]]);
      taken[d]++;
      deficit--;
      progressed = true;
    }
  }
  if (!progressed) break; // global pool exhausted
}

selected.sort((a, b) => a.slug.localeCompare(b.slug));
const slugs = selected.map((s) => s.slug);
// slug → MVP destination, so content-build can stamp activity.mvpDestination
// and the /activities filter can offer the 5 destinations (not 15 raw regions).
const bySlug = Object.fromEntries(selected.map((s) => [s.slug, s.dest]));

// ─── Report ───────────────────────────────────────────────────────────────────
const distribution = Object.fromEntries(ACTIVE_DESTS.map((d) => [d, taken[d]]));
const report = {
  generatedAt: new Date().toISOString(),
  requestedCount: COUNT,
  selectedCount: slugs.length,
  destinations: ACTIVE_DESTS,
  distribution,
  poolDepth: Object.fromEntries(ACTIVE_DESTS.map((d) => [d, buckets[d].length])),
  criteria: stats,
  withPriceData: selected.filter((s) => s.priced).length,
  curatedPhoto: selected.filter((s) => s.photo === "curated").length,
};

console.log("\n─── MVP selection ───────────────────────────────────────────");
console.log(`Catalogue total .............. ${stats.total}`);
console.log(`Failed: no confirmed photo ... ${stats.failedPhoto}`);
console.log(`Failed: no real marketplace .. ${stats.failedMarketplace}`);
console.log(`Failed: no destination match . ${stats.unmatchedDestination}`);
console.log(`Eligible pool ................ ${stats.eligible}`);
console.log(`Requested .................... ${COUNT}`);
console.log(`Selected ..................... ${slugs.length}`);
console.log("Distribution:");
for (const d of ACTIVE_DESTS) {
  console.log(`  ${d.padEnd(12)} ${String(taken[d]).padStart(3)}  (pool ${buckets[d].length})`);
}
console.log(`With price data .............. ${report.withPriceData}/${slugs.length}`);
console.log(`Curated (non-SA) photo ....... ${report.curatedPhoto}/${slugs.length}`);
if (slugs.length < COUNT) {
  console.log(`⚠  Pool exhausted — selected ${slugs.length} of requested ${COUNT}.`);
}
console.log("──────────────────────────────────────────────────────────────\n");

if (DRY_RUN) {
  console.log("--dry-run: no files written.");
  process.exit(0);
}

writeFileSync(
  OUT_ALLOWLIST,
  JSON.stringify(
    {
      _comment:
        "Generated by scripts/select-mvp-activities.mjs. Phase 1 MVP allow-list. content-build.mjs stamps activity.mvp from `slugs` and activity.mvpDestination from `bySlug`. Re-run the script to regenerate; edit by hand only as a stopgap.",
      generatedAt: report.generatedAt,
      count: slugs.length,
      destinations: ACTIVE_DESTS,
      distribution,
      slugs,
      bySlug,
    },
    null,
    2,
  ) + "\n",
);
writeFileSync(OUT_REPORT, JSON.stringify(report, null, 2) + "\n");

console.log(`✓ Wrote ${slugs.length} slugs → src/data/mvp-slugs.json`);
console.log(`✓ Wrote report → .content/mvp-selection-report.json`);
console.log("→ Next: run `npm run content:build` to stamp activity.mvp.\n");
